import type {
  ScaleLinear,
  ScaleLogarithmic,
  ScaleSymLog,
  ScaleTime,
} from 'd3-scale';
import { isNumber } from 'lodash-es';

import { isRangeMarker } from './is-range-marker.js';
import { MINIMUM_MARKER_WIDTH } from '../constants.js';
import type { AnnotationsMarkerConfig } from '../types/annotations-marker-props.js';

export const calculateMarkerDimension = (
  marker: AnnotationsMarkerConfig,
  scale:
    | ScaleTime<number, number>
    | ScaleLinear<number, number>
    | ScaleLogarithmic<number, number>
    | ScaleSymLog<number, number>,
) => {
  let x: number;
  const isReversed = scale.domain()[0] > scale.domain()[1];
  const finishMarker = marker.end ?? marker.start;
  const start = isReversed ? finishMarker : marker.start;
  const end = isReversed ? marker.start : finishMarker;

  if (isNumber(start)) {
    x = scale(start) ?? 0;
  } else {
    x = scale(start.getTime()) ?? 0;
  }

  let width = 0;

  if (isRangeMarker(marker)) {
    let x1: number;

    if (isNumber(end)) {
      x1 = scale(end) ?? 0;
    } else {
      x1 = scale(end.getTime()) ?? 0;
    }

    width = calculateMarkerWidth(x, x1);
  }

  return { x, width };
};

const calculateMarkerWidth = (x0: number, x1: number) => {
  const width = x1 - x0;

  if (width < MINIMUM_MARKER_WIDTH) {
    return MINIMUM_MARKER_WIDTH;
  }

  return width;
};
